SELECT CadastroAcolhidos.CódigoAcolhido, CadastroAcolhidos.NomeAcolhido, CadastroAcolhidos.MaeAcolhido, CadastroAcolhidos.PaiAcolhido, CadastroAcolhidos.DataNascimentoAcolhido, CadastroAcolhidos.IdadeAcolhido, CadastroAcolhidos.DataAcolhimento, [Entidades de Acolhimento].NomeEntidade, CadastroAcolhidos.PeriodoAcolhimento, CadastroAcolhidos.MotivoAcolhimento, CadastroAcolhidos.NPedProv, CadastroAcolhidos.NDestituicao, CadastroAcolhidos.NGuiaAcolhimento, CadastroAcolhidos.DataDesacolhimento, CadastroAcolhidos.AcolhidoEvadido, CadastroAcolhidos.DataEvasão, CadastroAcolhidos.AcolhidoDestituido, CadastroAcolhidos.DataDestituição, CadastroAcolhidos.DataTransito, CadastroAcolhidos.FaseProcessual, CadastroAcolhidos.ImpulsoProcessual, CadastroAcolhidos.Observações
FROM CadastroAcolhidos INNER JOIN [Entidades de Acolhimento] ON CadastroAcolhidos.EntidadeAcolhimento = [Entidades de Acolhimento].NomeEntidade
WHERE ((([Entidades de Acolhimento].NomeEntidade)="Casa Lar Dorcas") AND ((CadastroAcolhidos.DataDesacolhimento) Is Null));
